    private static final int READ_TIMEOUT = 10000;   // 10 seconds

    /**
     * Downloads an image from a URL and verifies if it is a valid image format.
     *
     * @param imageUrl The URL of the image to process.
     * @return true if the image is valid and can be read; false otherwise.
     */
    public boolean processImageFromUrl(String imageUrl) {
        if (imageUrl == null || imageUrl.trim().isEmpty()) {
            return false;
        }

        HttpURLConnection connection = null;
        try {
            URL url = new URL(imageUrl);

            // Security: Restrict protocols to HTTP and HTTPS to prevent local file access (SSRF protection)
            String protocol = url.getProtocol();
            if (!"http".equalsIgnoreCase(protocol) && !"https".equalsIgnoreCase(protocol)) {
                return false;
            }

            connection = (HttpURLConnection) url.openConnection();

            // Security: Set timeouts to prevent Denial of Service (DoS) via slow connections
            connection.setConnectTimeout(CONNECT_TIMEOUT);
            connection.setReadTimeout(READ_TIMEOUT);

            // Handle redirects explicitly or rely on default (default is usually true for HttpURLConnection)
            connection.setInstanceFollowRedirects(true);
            connection.setRequestMethod("GET");

            // Connect to the resource
            connection.connect();

            // Verify HTTP response code
            int responseCode = connection.getResponseCode();
            if (responseCode != HttpURLConnection.HTTP_OK) {
                return false;
            }

            // Optimization & Security: Check Content-Type header before downloading the body
            String contentType = connection.getContentType();
            if (contentType == null || !contentType.startsWith("image/")) {
                return false;
            }

            // Attempt to read the image
            try (InputStream inputStream = connection.getInputStream()) {
                // ImageIO.read returns null if no registered ImageReader can decode the stream
                BufferedImage image = ImageIO.read(inputStream);
                return image != null;
            }

        } catch (Exception e) {
            // Catching Exception covers IOException, MalformedURLException, and IllegalArgumentException
            // In a production environment, this should be logged
            return false;
        } finally {
            if (connection != null) {
                connection.disconnect();
            }
        }
    }
}
